class Solution:
    def minTrioDegree(self, n, edges):
        adj = [[False] * (n + 1) for _ in range(n + 1)]
        deg = [0] * (n + 1)
        for u, v in edges:
            adj[u][v] = True
            adj[v][u] = True
            deg[u] += 1
            deg[v] += 1
        best = -1
        for a in range(1, n + 1):
            for b in range(a + 1, n + 1):
                if not adj[a][b]:
                    continue
                for c in range(b + 1, n + 1):
                    if adj[a][c] and adj[b][c]:
                        d = deg[a] + deg[b] + deg[c] - 6
                        if best == -1 or d < best:
                            best = d
        return best

