class Solution:
    def minTrioDegree(self, n, edges):
        adj = [[False] * (n + 1) for _ in range(n + 1)]
        deg = [0] * (n + 1)
        nbrs = [[] for _ in range(n + 1)]
        for u, v in edges:
            adj[u][v] = True
            adj[v][u] = True
            deg[u] += 1
            deg[v] += 1
            nbrs[min(u, v)].append(max(u, v))
        best = float('inf')
        for u, v in edges:
            a, b = (u, v) if u < v else (v, u)
            for c in nbrs[a]:
                if c != b and adj[b][c]:
                    d = deg[a] + deg[b] + deg[c] - 6
                    if d < best:
                        best = d
        return -1 if best == float('inf') else best

