var minTrioDegree = function(n, edges) {
    const adj = Array.from({length: n + 1}, () => new Array(n + 1).fill(false));
    const deg = new Array(n + 1).fill(0);
    const nbrs = Array.from({length: n + 1}, () => []);
    for (const [u, v] of edges) {
        adj[u][v] = true;
        adj[v][u] = true;
        deg[u]++;
        deg[v]++;
        nbrs[Math.min(u, v)].push(Math.max(u, v));
    }
    let best = Infinity;
    for (const [u, v] of edges) {
        const a = Math.min(u, v), b = Math.max(u, v);
        for (const c of nbrs[a]) {
            if (c !== b && adj[b][c]) {
                const d = deg[a] + deg[b] + deg[c] - 6;
                if (d < best) best = d;
            }
        }
    }
    return best === Infinity ? -1 : best;
};
